package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClassMock;

  @BeforeAll
  static void setup() {
    recordClassMock = RecordClassMock.class;
  }

  @Test
  void testGetRecordComponentNames_returnsExpectedNames() {
    try (MockedStatic<ReflectionHelper.RecordHelper> mockedRecordHelperStatic = Mockito.mockStatic(ReflectionHelper.RecordHelper.class, Mockito.CALLS_REAL_METHODS)) {
      ReflectionHelper.RecordHelper recordHelperSpy = mock(ReflectionHelper.RecordHelper.class);
      mockedRecordHelperStatic.when(() -> ReflectionHelper.RECORD_HELPER).thenReturn(recordHelperSpy);
      String[] expected = new String[] {"component1", "component2"};
      when(recordHelperSpy.getRecordComponentNames(recordClassMock)).thenReturn(expected);

      String[] actual = ReflectionHelper.getRecordComponentNames(recordClassMock);

      assertArrayEquals(expected, actual);
      verify(recordHelperSpy).getRecordComponentNames(recordClassMock);
    }
  }

  // Dummy record class for testing
  private record RecordClassMock(String component1, int component2) {}
}
